-- پرامپت پالایش: فقط سیاست دبیری برای مدیر؛ مونتاژ فنی در کد (news_editorial_v1)

UPDATE tbl_app_prompts SET
  description_fa = 'فقط سیاست‌های تشخیص اهمیت، کیفیت، مرتبط/غیرمرتبط و دسته‌بندی — بدون متغیر فنی',
  body = E'سیاست‌های تشخیص اهمیت:\n- اخبار مرتبط با حوزه موشکی، پدافند و ارتباطات نظامی، درجه اهمیت بالاتری دارند.\n- اخبار آب‌وهوا و هشدارهای محیطی در صورت تأثیر بر عملیات یا ایمنی عمومی، اهمیت متوسط تا بالا دارند.\n- اخبار صرفاً تبلیغاتی، سرگرمی یا بی‌ارتباط با حوزه خبری سازمان: غیرمرتبط و اولویت پایین.\n\nسیاست‌های تشخیص کیفیت:\n- منبع نامشخص یا متن مبهم: کیفیت پایین.\n- خبر با منبع روشن و متن قابل اتکا: کیفیت متوسط تا بالا.\n\nسیاست دسته‌بندی:\n- موضوع امنیتی/نظامی → security یا military\n- موضوع سیاسی داخلی/خارجی → political یا international\n- در صورت ابهام، نزدیک‌ترین دسته را انتخاب کنید.'
WHERE prompt_key = 'news.editorial.policy';

UPDATE tbl_ai_form_actions SET assembly_strategy = 'news_editorial_v1'
WHERE form_name = 'news_editorial_batch' AND action_name = 'run_editorial';
